+        if (auto *UI = dyn_cast<Instruction>(U)) {
+          if (L->contains(UI) && UI->getParent() != ExitingBlock) {
+            if (auto *Branch = dyn_cast<BranchInst>(UI)) {
+              if (Branch->isConditional())
